        '\uccb4\ub825\u00b7\uc815\uc2e0\ub825\u00b7\uc720\ub300 \uc2a4\ud0ef \uc2dc\uc2a4\ud15c\uc73c\ub85c \ud50c\ub808\uc774\uc5b4\uc758 \uc120\ud0dd\uc774 \ubc18\uc601\ub429\ub2c8\ub2e4',
